frappe.web_form.after_load = () => {
    frappe.web_form.set_df_property('extra_details', 'hidden', 1);

    const urlParams = new URLSearchParams(window.location.search);
    const referrer = urlParams.get('ref');
    if (referrer) {
        frappe.web_form.set_value('referred_by', referrer);
        window.current_referrer = referrer;
    }

    setupRegistrationSaveWrapper();

    setTimeout(() => {
        setupSplitLayout();
        setupBannerImage();
        injectCustomQuestions();
        setupPhoneValidation();
    }, 200);
};

function setupSplitLayout() {
    if (document.getElementById('umbrella-form-layout')) return;

    const banner = document.querySelector('.web-form-banner-image');
    if (!banner) return;

    const bannerWrapper = banner.closest('.web-form-banner') || banner.parentElement;
    const webFormRoot =
        document.querySelector('.web-form') ||
        document.querySelector('.web-form-container') ||
        bannerWrapper?.parentElement;

    if (!webFormRoot || !bannerWrapper) return;

    const layout = document.createElement('div');
    layout.id = 'umbrella-form-layout';
    layout.className = 'umbrella-form-layout';

    const bannerCol = document.createElement('div');
    bannerCol.className = 'umbrella-banner-column';

    const contentCol = document.createElement('div');
    contentCol.className = 'umbrella-content-column';

    bannerCol.appendChild(bannerWrapper);

    const children = Array.from(webFormRoot.children).filter((el) => el !== bannerWrapper);
    children.forEach((child) => contentCol.appendChild(child));

    layout.appendChild(bannerCol);
    layout.appendChild(contentCol);
    webFormRoot.appendChild(layout);
}

function setupBannerImage() {
    const img = document.querySelector('.umbrella-banner-column .web-form-banner-image');
    if (!img || img.dataset.bannerReady) return;

    img.dataset.bannerReady = '1';
    const bannerWrapper = img.closest('.web-form-banner') || img.parentElement;

    img.removeAttribute('height');
    img.removeAttribute('width');
    img.style.removeProperty('max-height');
    img.style.removeProperty('object-fit');

    const resetBannerStyles = () => {
        const isMobile = window.matchMedia('(max-width: 768px)').matches;

        if (bannerWrapper) {
            bannerWrapper.style.setProperty('display', 'block', 'important');
            bannerWrapper.style.setProperty('visibility', 'visible', 'important');
            bannerWrapper.style.setProperty('height', 'auto', 'important');
            bannerWrapper.style.setProperty('max-height', 'none', 'important');
            bannerWrapper.style.setProperty('overflow', 'visible', 'important');
        }

        img.style.setProperty('display', 'block', 'important');
        img.style.setProperty('visibility', 'visible', 'important');
        img.style.setProperty('width', '100%', 'important');
        img.style.setProperty('height', 'auto', 'important');
        img.style.setProperty('max-height', 'none', 'important');
        img.style.setProperty('max-width', '100%', 'important');
        img.style.setProperty('object-fit', 'contain', 'important');
        img.style.setProperty('position', 'static', 'important');

        if (isMobile) {
            img.style.setProperty('min-height', 'auto', 'important');
        }
    };

    const scheduleReset = () => requestAnimationFrame(resetBannerStyles);

    if (img.complete) {
        scheduleReset();
    } else {
        img.addEventListener('load', scheduleReset, { once: true });
    }

    window.addEventListener('resize', scheduleReset);
    window.addEventListener('orientationchange', scheduleReset);
}

function injectCustomQuestions() {
    const parent =
        document.querySelector('.umbrella-content-column .web-form-body') ||
        document.querySelector('.web-form-body') ||
        document.querySelector('.form-body') ||
        document.querySelector('form');

    if (!parent || document.getElementById('manual-custom-questions')) return;

    const custom_section = document.createElement('div');
    custom_section.id = 'manual-custom-questions';
    custom_section.className = 'web-form-container';

    custom_section.innerHTML = `
        <div class="frappe-control" style="margin-bottom: var(--margin-md);">
            <div class="form-group">
                <label class="control-label">Have you joined the <a href="https://chat.whatsapp.com/Env3dFGaJrQLMRZNpyEcEf" style="color: #28a745; font-weight: bold;" target="_blank">WhatsApp Group</a>? (Click on the green text to get updates)</label>
                <div class="checkbox">
                    <label>
                        <input type="checkbox" id="custom_whatsapp">
                        <span class="label-area" style="margin-left: 8px;">Yes, I have joined the above group</span>
                    </label>
                </div>
            </div>
        </div>

        <div class="frappe-control" style="margin-bottom: var(--margin-md);">
            <div class="form-group">
                <label class="control-label">Number of umbrellas you'd like to distribute</label>
                <select id="custom_umbrellas" class="form-control">
                    <option value="5">5</option>
                    <option value="10">10</option>
                    <option value="15">15</option>
                    <option value="20">20</option>
                </select>
            </div>
        </div>

        <div id="residential_wrapper" class="frappe-control" style="margin-bottom: var(--margin-md);">
            <div class="form-group">
                <label class="control-label">Residential Address (for doorstep delivery of the umbrellas) <span class="text-danger">*</span></label>
                <textarea id="custom_residential_address" class="form-control" rows="3" placeholder="Enter your full home address..."></textarea>
            </div>
        </div>

        <div class="frappe-control" style="margin-bottom: var(--margin-md);">
            <div class="form-group">
                <label class="control-label">Do you have a T-shirt?</label>
                <div class="pill-group" id="custom_tshirt_have_group" role="group" aria-label="T-shirt ownership">
                    <button type="button" class="btn btn-secondary btn-sm pill" data-value="have">I have</button>
                    <button type="button" class="btn btn-secondary btn-sm pill" data-value="dont_have">I don't have</button>
                </div>
                <input type="hidden" id="custom_tshirt_have" value="">
            </div>
        </div>

        <div id="tshirt_size_wrapper" class="collapse-section">
            <div class="collapse-inner">
                <div class="frappe-control">
                    <div class="form-group">
                        <label class="control-label">T-shirt Size (if in doubt, choose the bigger size)</label>
                        <select id="custom_tshirt" class="form-control">
                            <option value="">Select a size</option>
                            <option value="XS">XS</option>
                            <option value="S">S</option>
                            <option value="M">M</option>
                            <option value="L">L</option>
                            <option value="XL">XL</option>
                            <option value="XXL">XXL</option>
                        </select>
                    </div>
                </div>
            </div>
        </div>

        <div class="frappe-control" style="margin-bottom: var(--margin-md);">
            <div class="form-group">
                <label class="control-label">Would you like to take an extra step and be a part of the core team?</label>
                <select id="custom_committee" class="form-control">
                    <option value="Capital Champion">Capital Champion – Help raise funds for sourcing umbrellas</option>
                    <option value="Impact Multiplier">Impact Multiplier – Inspire 5+ people to participate</option>
                    <option value="Other">Other ideas (share below)</option>
                    <option value="Later">Perhaps, next time</option>
                </select>
            </div>
        </div>

        <div id="ideas_wrapper" class="collapse-section">
            <div class="collapse-inner">
                <div class="frappe-control">
                    <div class="form-group">
                        <label class="control-label">Share your ideas or suggestions for this event <span class="text-danger">*</span></label>
                        <textarea id="custom_ideas" class="form-control" rows="3" placeholder="What's on your mind?"></textarea>
                    </div>
                </div>
            </div>
        </div>
    `;

    parent.append(custom_section);
    setupTshirtPills();
    setupCommitteeToggle();
}

function toggleCollapse(el, show) {
    if (!el) return;
    el.classList.toggle('is-visible', show);
}

function setupTshirtPills() {
    const pillGroup = document.getElementById('custom_tshirt_have_group');
    const hiddenInput = document.getElementById('custom_tshirt_have');
    const sizeWrapper = document.getElementById('tshirt_size_wrapper');
    const sizeSelect = document.getElementById('custom_tshirt');

    if (!pillGroup || !hiddenInput || !sizeWrapper) return;

    const setPillState = (pill, isActive) => {
        pill.classList.toggle('active', isActive);
        pill.classList.toggle('btn-primary', isActive);
        pill.classList.toggle('btn-secondary', !isActive);
    };

    pillGroup.querySelectorAll('.pill').forEach((pill) => {
        pill.addEventListener('click', () => {
            pillGroup.querySelectorAll('.pill').forEach((p) => setPillState(p, false));
            setPillState(pill, true);

            const value = pill.dataset.value;
            hiddenInput.value = value;

            if (value === 'dont_have') {
                toggleCollapse(sizeWrapper, true);
            } else {
                toggleCollapse(sizeWrapper, false);
                if (sizeSelect) sizeSelect.value = '';
            }
        });
    });
}

function setupCommitteeToggle() {
    const committee = document.getElementById('custom_committee');
    const ideasWrapper = document.getElementById('ideas_wrapper');
    const ideasField = document.getElementById('custom_ideas');

    if (!committee || !ideasWrapper) return;

    const updateIdeasVisibility = () => {
        const show = committee.value === 'Other';
        toggleCollapse(ideasWrapper, show);
        if (!show && ideasField) ideasField.value = '';
    };

    committee.addEventListener('change', updateIdeasVisibility);
    updateIdeasVisibility();
}

function findPhoneInput() {
    const selectors = [
        'input[data-fieldname="temp_phone"]',
        'input[data-fieldname="mobile_no"]',
        'input[data-fieldname="phone"]',
        'input[data-fieldname="contact_number"]',
        'input[name="temp_phone"]',
        'input[name="mobile_no"]',
        'input[name="phone"]',
        'input[type="tel"]',
    ];

    for (const selector of selectors) {
        const input = document.querySelector(selector);
        if (input) return input;
    }

    const labels = document.querySelectorAll('.control-label, label');
    for (const label of labels) {
        if (/phone|mobile|contact/i.test(label.textContent)) {
            const control = label.closest('.frappe-control');
            const input = control?.querySelector('input');
            if (input) return input;
        }
    }

    return null;
}

function normalizePhone(value) {
    return (value || '').replace(/\D/g, '').replace(/^91/, '').slice(0, 10);
}

function isValidPhone(value) {
    const digits = normalizePhone(value);
    return /^[6-9]\d{9}$/.test(digits);
}

const REGISTRATION_CHECK_METHOD =
    'volunteering.volunteering.doctype.participation.participation.check_event_registration';

function getEventId() {
    return frappe.web_form.get_value('form_placeholder') || frappe.web_form.doc?.form_placeholder || '';
}

function getPhoneValue() {
    const input = findPhoneInput();
    const fromInput = input?.value?.trim();
    if (fromInput) return fromInput;
    return frappe.web_form.get_value('temp_phone') || '';
}

function getPhoneControl() {
    const input = findPhoneInput();
    return input?.closest('.frappe-control') || input?.parentElement || null;
}

function showRegistrationError() {
    const control = getPhoneControl();
    const input = findPhoneInput();
    if (!control || !input) return;

    let errorEl = control.querySelector('.field-registration-error');
    if (!errorEl) {
        errorEl = document.createElement('div');
        errorEl.className = 'field-live-error field-registration-error';
        errorEl.setAttribute('role', 'alert');
        errorEl.textContent = 'You have already registered for this event.';
        control.appendChild(errorEl);
    }

    input.classList.add('is-invalid');
    input.classList.remove('is-valid');
    errorEl.classList.add('is-visible');
    window.registrationBlocked = true;
}

function clearRegistrationError() {
    const control = getPhoneControl();
    control?.querySelector('.field-registration-error')?.classList.remove('is-visible');
    window.registrationBlocked = false;
}

function checkAlreadyRegistered(mobile) {
    const event = getEventId();
    if (!mobile || !event) {
        return Promise.resolve({ registered: false });
    }

    return frappe.xcall(REGISTRATION_CHECK_METHOD, { mobile, event });
}

let registrationCheckInFlight = false;

function runRegistrationCheckOnBlur() {
    const phoneValue = getPhoneValue();
    if (!isValidPhone(phoneValue)) {
        clearRegistrationError();
        return;
    }

    if (registrationCheckInFlight) return;
    registrationCheckInFlight = true;

    checkAlreadyRegistered(phoneValue)
        .then((result) => {
            if (result?.registered) {
                showRegistrationError();
            } else {
                clearRegistrationError();
            }
        })
        .finally(() => {
            registrationCheckInFlight = false;
        });
}

function setupRegistrationSaveWrapper() {
    if (frappe.web_form._registrationSaveWrapped) return;
    frappe.web_form._registrationSaveWrapped = true;

    const originalSave = frappe.web_form.save.bind(frappe.web_form);

    frappe.web_form.save = function () {
        const syncValid = frappe.web_form.validate && frappe.web_form.validate();
        if (!syncValid && syncValid !== undefined) {
            return false;
        }

        const phone = getPhoneValue();
        if (!phone || !isValidPhone(phone)) {
            return false;
        }

        frappe.call({
            method: REGISTRATION_CHECK_METHOD,
            args: { mobile: phone, event: getEventId() },
            freeze: true,
            callback: (r) => {
                if (r.message?.registered) {
                    showRegistrationError();
                    frappe.msgprint(__('You have already registered for this event.'));
                    return;
                }
                originalSave();
            },
        });
        return false;
    };
}

function setupPhoneValidation() {
    const input = findPhoneInput();
    if (!input || input.dataset.liveValidationBound) return;

    input.dataset.liveValidationBound = '1';
    input.setAttribute('inputmode', 'numeric');
    input.setAttribute('autocomplete', 'tel');

    const control = input.closest('.frappe-control') || input.parentElement;
    let errorEl = control?.querySelector('.field-live-error');

    if (!errorEl && control) {
        errorEl = document.createElement('div');
        errorEl.className = 'field-live-error';
        errorEl.setAttribute('role', 'alert');
        errorEl.textContent = 'Please enter a valid 10-digit mobile number.';
        control.appendChild(errorEl);
    }

    const validate = () => {
        const raw = input.value.trim();

        if (!raw) {
            input.classList.remove('is-invalid', 'is-valid');
            errorEl?.classList.remove('is-visible');
            return false;
        }

        const valid = isValidPhone(raw);

        input.classList.toggle('is-invalid', !valid);
        input.classList.toggle('is-valid', valid);
        errorEl?.classList.toggle('is-visible', !valid);

        return valid;
    };

    input.addEventListener('input', () => {
        const digits = normalizePhone(input.value);
        if (input.value !== digits && digits.length <= 10) {
            const cursor = input.selectionStart;
            input.value = digits;
            input.setSelectionRange(cursor, cursor);
        }
        clearRegistrationError();
        validate();
    });

    input.addEventListener('blur', () => {
        const valid = validate();
        if (valid) {
            runRegistrationCheckOnBlur();
        } else {
            clearRegistrationError();
        }
    });
    window.validatePhoneField = validate;
}

frappe.web_form.validate = () => {
    const getVal = (id) => document.getElementById(id)?.value || '';
    const getSelectedText = (id) => {
        const e = document.getElementById(id);
        return e ? e.options[e.selectedIndex].text : '';
    };

    if (window.registrationBlocked) {
        frappe.msgprint(__('You have already registered for this event.'));
        return false;
    }

    if (window.current_referrer) {
        frappe.web_form.doc.referred_by = window.current_referrer;
    }

    const phoneInput = findPhoneInput();
    const phoneValue = phoneInput?.value?.trim() || '';

    if (!phoneValue) {
        frappe.msgprint(__('Please enter your phone number.'));
        phoneInput?.focus();
        return false;
    }

    if (!isValidPhone(phoneValue)) {
        frappe.msgprint(__('Please enter a valid 10-digit mobile number.'));
        phoneInput?.classList.add('is-invalid');
        phoneInput?.closest('.frappe-control')
            ?.querySelector('.field-live-error')
            ?.classList.add('is-visible');
        phoneInput?.focus();
        return false;
    }

    const joined = document.getElementById('custom_whatsapp')?.checked || false;
    const umbrellas = getVal('custom_umbrellas');
    const residential_addr = getVal('custom_residential_address');
    const tshirtStatus = getVal('custom_tshirt_have');
    const committeeValue = getVal('custom_committee');

    if (!joined) {
        frappe.msgprint(__('Please join the WhatsApp group to continue.'));
        return false;
    }

    if (!residential_addr.trim()) {
        frappe.msgprint(__('Please provide your residential address for doorstep delivery.'));
        return false;
    }

    let tshirtAnswer = '';
    if (tshirtStatus === 'have') {
        tshirtAnswer = 'Already have T-shirt';
    } else if (tshirtStatus === 'dont_have') {
        const size = getVal('custom_tshirt');
        if (!size) {
            frappe.msgprint(__('Please select your T-shirt size.'));
            return false;
        }
        tshirtAnswer = size;
    } else {
        frappe.msgprint(__('Please answer whether you have a T-shirt.'));
        return false;
    }

    const ideas = getVal('custom_ideas');
    if (committeeValue === 'Other' && !ideas.trim()) {
        frappe.msgprint(__('Please share your ideas or suggestions.'));
        toggleCollapse(document.getElementById('ideas_wrapper'), true);
        document.getElementById('custom_ideas')?.focus();
        return false;
    }

    frappe.web_form.doc.kits_requested = parseInt(umbrellas);
    frappe.web_form.doc.temp_address = residential_addr;

    const details = [];
    details.push({ question: 'Joined WhatsApp Group', answer: joined ? 'Yes' : 'No' });
    details.push({ question: 'Number of Umbrellas', answer: umbrellas });
    details.push({ question: 'T-shirt', answer: tshirtAnswer });
    details.push({ question: 'Organizing Committee Role', answer: getSelectedText('custom_committee') });

    if (ideas.trim()) {
        details.push({ question: 'Volunteer Ideas/Suggestions', answer: ideas });
    }

    frappe.web_form.doc.extra_details = details;

    return true;
};
